               <button onClick={() => setArtisanProfile(null)} className="absolute -right-2 -top-2 bg-rose-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity shadow-lg hover:bg-rose-600">
                 <X className="w-2.5 h-2.5" />
               </button>
