                      {c}
                    </button>
                  ))}
                </div>
              </div>

              {/* Reference Blueprint (Source Image) */}
              <div className="space-y-10">
                <div className="flex items-center justify-between">
                  <label className="flex items-center gap-4 text-[11px] font-black uppercase tracking-[0.4em] text-gray-300">
                    <ImageIcon className="w-4 h-4" /> 02 / Reference Blueprint
                  </label>
                  {sourceImage && (
                    <button 
                      onClick={() => setSourceImage(null)}
                      className="text-[10px] font-black text-rose-500 uppercase tracking-widest flex items-center gap-2 hover:text-rose-700 transition-colors"
                    >
                      <X className="w-3 h-3" /> Clear Base
