                {!sourceImage ? (
                  <button 
                    onClick={() => sourceImageInputRef.current?.click()}
                    className="w-full h-40 border-2 border-dashed border-gray-100 rounded-[2.5rem] flex flex-col items-center justify-center gap-4 bg-[#fcfcfb] hover:bg-amber-50 hover:border-amber-200 transition-all group"
                  >
                    <div className="p-4 bg-white rounded-2xl shadow-sm group-hover:scale-110 transition-transform">
                      <UploadCloud className="w-6 h-6 text-gray-300 group-hover:text-amber-900" />
                    </div>
                    <span className="text-[10px] font-black uppercase tracking-widest text-gray-400 group-hover:text-amber-900">Upload Structural Base (Image-to-Image)</span>
                  </button>
                ) : (
                  <div className="relative w-full h-48 rounded-[2.5rem] overflow-hidden border border-black/5 group shadow-xl">
                    <img src={sourceImage} alt="Structural base" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                    <div className="absolute inset-0 bg-black/40 backdrop-blur-sm flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => sourceImageInputRef.current?.click()}
                        className="bg-white text-black px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-2xl"
                      >
                        <RefreshCcw className="w-4 h-4" /> Replace Blueprint
                      </button>
                    </div>
                    <div className="absolute top-4 left-4 flex items-center gap-2 px-3 py-1.5 bg-amber-950 text-white rounded-full text-[8px] font-black uppercase tracking-widest shadow-lg">
                      <Layers className="w-2.5 h-2.5" /> Base Structure Active
                    </div>
                  </div>
                )}
              </div>

              {/* Motif Library */}
              <div className="space-y-12">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-8">
                  <label className="flex items-center gap-4 text-[11px] font-black uppercase tracking-[0.4em] text-gray-300">
                    <Dna className="w-4 h-4" /> 03 / Motif Library
                  </label>
                  <div className="flex gap-4">
                    <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-3 px-6 py-3 bg-gray-50 rounded-2xl border border-gray-100 text-[10px] font-bold text-gray-500 uppercase tracking-widest hover:bg-amber-50 hover:text-amber-950 transition-all">
                      <FolderPlus className="w-4 h-4" /> Add Assets
                    </button>
                  </div>
                </div>

                <div className="grid grid-cols-2 sm:grid-cols-4 gap-6">
                  {filteredMotifs.map(motif => (
                    <MotifCard 
                      key={motif.id}
                      motif={motif}
                      isSelected={selectedMotifIds.includes(motif.id)}
                      onSelect={toggleMotifSelection}
                    />
                  ))}
                </div>
              </div>

              {/* Config Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-16 pt-10">
                 <div className="space-y-8">
                    <label className="flex items-center gap-4 text-[11px] font-black uppercase tracking-[0.4em] text-gray-300">
                      <Palette className="w-4 h-4" /> 04 / Master Palette
                    </label>
                    <PaletteSelector 
                      palettes={allPalettes} 
                      selectedPaletteName={selectedPalette} 
                      onSelect={setSelectedPalette} 
                      onAddPalette={(p) => setCustomPalettes(prev => [...prev, p])}
                      onDeletePalette={(name) => setCustomPalettes(prev => prev.filter(p => p.name !== name))}
                    />
                 </div>

                 <div className="space-y-8">
                    <label className="flex items-center gap-4 text-[11px] font-black uppercase tracking-[0.4em] text-gray-300">
                      <Grid3X3 className="w-4 h-4" /> 05 / Repeat Logic
                    </label>
                    <div className="flex gap-4 p-2 bg-[#fcfcfb] rounded-[2.5rem] border border-gray-100">
                      {(['Grid', 'Half-Drop', 'Brick'] as const).map(type => (
                        <button
                          key={type}
                          onClick={() => setRepeatType(type)}
                          className={`flex-1 py-5 rounded-[1.8rem] text-[10px] font-black uppercase tracking-widest transition-all ${
                            repeatType === type ? 'bg-white text-amber-950 shadow-xl border border-black/5' : 'text-gray-400 hover:text-amber-800'
                          }`}
                        >
                          {type}
                        </button>
                      ))}
                    </div>
                 </div>
              </div>

              {/* Granular Complexity Control */}
              <div className="space-y-10 pt-4">
                <label className="flex items-center gap-4 text-[11px] font-black uppercase tracking-[0.4em] text-gray-300">
                  <Fingerprint className="w-4 h-4" /> 06 / Detail Complexity
                </label>
                <div className="grid grid-cols-3 gap-6">
                  {(['Minimal', 'Balanced', 'Maximal'] as const).map(lvl => (
                    <button
                      key={lvl}
                      onClick={() => setComplexity(lvl)}
                      className={`relative overflow-hidden py-10 rounded-[2.5rem] border-2 transition-all active:scale-95 group ${
                        complexity === lvl 
                          ? 'bg-amber-950 border-amber-950 text-white shadow-2xl translate-y-[-4px]' 
                          : 'bg-[#fcfcfb] border-transparent text-gray-400 hover:border-amber-200 hover:text-amber-900'
                      }`}
                    >
                      <div className="flex flex-col items-center gap-3">
                         <div className={`w-8 h-8 rounded-full flex items-center justify-center border-2 ${complexity === lvl ? 'border-amber-400/50 bg-amber-400/10' : 'border-gray-200 group-hover:border-amber-200'}`}>
                           {lvl === 'Minimal' && <div className="w-2 h-2 rounded-full bg-current" />}
                           {lvl === 'Balanced' && (
                             <div className="flex gap-0.5">
                               <div className="w-1.5 h-1.5 rounded-full bg-current" />
                               <div className="w-1.5 h-1.5 rounded-full bg-current" />
                             </div>
                           )}
                           {lvl === 'Maximal' && (
                             <div className="grid grid-cols-2 gap-0.5">
                               <div className="w-1.5 h-1.5 rounded-full bg-current" />
                               <div className="w-1.5 h-1.5 rounded-full bg-current" />
                               <div className="w-1.5 h-1.5 rounded-full bg-current" />
                               <div className="w-1.5 h-1.5 rounded-full bg-current" />
                             </div>
                           )}
                         </div>
                         <span className="text-[10px] font-black uppercase tracking-[0.3em]">{lvl}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Action */}
              <div className="pt-10">
                <button
                  onClick={handleGenerate}
                  disabled={loading || selectedMotifIds.length === 0}
                  className="w-full bg-amber-950 text-white py-12 rounded-[3.5rem] font-black uppercase tracking-[0.6em] text-sm flex items-center justify-center gap-10 hover:bg-black transition-all shadow-[0_40px_80px_-20px_rgba(26,24,20,0.3)] active:scale-[0.98] group disabled:opacity-50 disabled:cursor-not-allowed overflow-hidden relative"
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
                  {loading ? (
                    <>
                      <RefreshCcw className="w-7 h-7 animate-spin" /> Synthesizing...
                    </>
                  ) : (
                    <>
                      Begin Synthesis
                      <Sparkles className="w-7 h-7 group-hover:scale-125 transition-transform" />
                    </>
                  )}
                </button>
                <div className="flex items-center justify-center gap-3 mt-10">
                  <Lock className="w-3.5 h-3.5 text-gray-300" />
                  <p className="text-[10px] font-black text-gray-300 uppercase tracking-[0.4em]">Secure Artisan Protocol V2.44</p>
                </div>
              </div>
            </section>
          </div>

          <div className="lg:col-span-5">
            <section className="sticky top-44 space-y-16">
              <div className="flex items-center justify-between">
                <h3 className="text-[11px] font-black uppercase tracking-[0.4em] text-gray-400 flex items-center gap-4">
                  <Activity className="w-4 h-4" /> Live Renderer
                </h3>
                {currentPattern && (
                  <div className="flex items-center gap-2 px-4 py-1.5 bg-emerald-50 text-emerald-700 rounded-full border border-emerald-100">
                    <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                    <span className="text-[9px] font-black uppercase tracking-widest">Active Synthesis</span>
                  </div>
                )}
              </div>

              <PreviewDisplay pattern={currentPattern} isGenerating={loading} />

              {history.length > 0 && (
                <div className="pt-20 border-t border-black/5 space-y-12">
                  <h3 className="text-[11px] font-black uppercase tracking-[0.4em] text-gray-400 flex items-center gap-4">
                    <History className="w-4 h-4" /> Studio Archive
                  </h3>
                  <div className="grid grid-cols-4 gap-6">
                    {history.slice(0, 8).map((item) => (
                      <button
                        key={item.id}
                        onClick={() => setCurrentPattern(item)}
                        className={`aspect-square rounded-[2rem] overflow-hidden border-[3px] transition-all active:scale-90 ${
                          currentPattern?.id === item.id ? 'border-amber-600 scale-110 shadow-2xl z-10' : 'border-transparent hover:border-amber-200 grayscale hover:grayscale-0'
