        culture,
        motif: motifNames,
        timestamp: Date.now(),
        config: { ...config }
      };
      setCurrentPattern(newPattern);
      setHistory(prev => [newPattern, ...prev]);
    } catch (error: any) {
      if (error?.message?.includes("Requested entity was not found")) {
        setHasApiKey(false);
        alert("API Key configuration error. Please authorize again.");
