export const PALETTES: ColorPalette[] = [
  { name: 'Traditional Madder', colors: ['#800000', '#000080', '#F5F5DC', '#000000'] },
  { name: 'Imperial Gold', colors: ['#FFD700', '#B8860B', '#8B4513', '#FFFFFF'] },
