    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      if (!file.type.startsWith('image/')) return;
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        const newMotif: Motif = {
          id: `usr_${Math.random().toString(36).substr(2, 9)}`,
          name: file.name.split('.')[0],
          description: `User-defined heritage asset.`,
          culture: culture === Culture.FUSION ? Culture.PAKISTAN : culture,
          previewUrl: base64,
          imageData: base64,
          isCustom: true
        };
        setCustomMotifs(prev => [newMotif, ...prev]);
        // Auto-select if slot available
        setSelectedMotifIds(prev => {
          if (prev.length < 4) return [...prev, newMotif.id];
          return prev;
        });
      };
      reader.readAsDataURL(file);
    });
    // Clear input so same file can be uploaded again
    e.target.value = '';
  };

  const handleSourceImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
