        artStyleId: selectedArtStyleId,
        customMotifs,
        artisanProfile: artisanProfile || undefined,
        sourceImage: sourceImages.length > 0 ? sourceImages[0] : undefined, // Using primary one for config storage
        aspectRatio,
        imageSize,
        seed,
        negativePrompt: negativePrompt || undefined
      };
      // Note: we can pass multiple images to the generator service if updated
      const result = await generateTextilePattern({
          ...config,
          sourceImage: sourceImages.length > 0 ? sourceImages[0] : undefined // Pass first for now as structural base
      });
      const motifNames = selectedMotifIds.map(id => [...MOTIFS, ...customMotifs].find(m => m.id === id)?.name || 'Design Block').join(' & ');
