interface PreviewDisplayProps {
  pattern: GeneratedPattern | null;
  isGenerating: boolean;
}

const PreviewDisplay: React.FC<PreviewDisplayProps> = ({ pattern, isGenerating }) => {
  const [isPreviewTiled, setIsPreviewTiled] = useState(false);
  const [zoom, setZoom] = useState(33.33);

  const tileStyle = useMemo(() => {
    if (!pattern || !isPreviewTiled) return {};

    const baseSize = `${zoom}%`;
    const url = `url(${pattern.imageUrl})`;
    const lowerPrompt = pattern.prompt.toLowerCase();

    // Standard Grid
    if (lowerPrompt.includes('grid')) {
       return {
         backgroundImage: url,
         backgroundSize: `${baseSize} ${baseSize}`,
         backgroundRepeat: 'repeat'
       };
    }

    // Half-Drop (Vertical Stagger)
    // CSS trick for staggered tiling
    if (lowerPrompt.includes('half-drop')) {
       return {
         backgroundImage: `${url}, ${url}`,
         backgroundSize: `${zoom * 2}% ${zoom * 2}%`,
         backgroundRepeat: 'repeat',
         // Offset second layer by 50%
         backgroundPosition: `0 0, ${zoom}% ${zoom}%`
       };
    }

    // Brick (Horizontal Stagger)
    if (lowerPrompt.includes('brick')) {
       return {
         backgroundImage: `${url}, ${url}`,
         backgroundSize: `${zoom * 2}% ${zoom * 2}%`,
         backgroundRepeat: 'repeat',
         // Offset second layer
         backgroundPosition: `0 0, ${zoom}% ${zoom}%`
       };
    }

    // Fallback standard repeat
    return {
      backgroundImage: url,
      backgroundSize: `${baseSize} ${baseSize}`,
      backgroundRepeat: 'repeat'
    };
  }, [pattern, isPreviewTiled, zoom]);

  if (isGenerating) {
