                isPreviewTiled 
                ? 'bg-amber-950 text-white' 
                : 'bg-white/95 backdrop-blur text-amber-950 hover:bg-white'
            }`}
          >
            <Repeat className={`w-6 h-6 ${isPreviewTiled ? 'rotate-180 transition-transform duration-500' : ''}`} />
