            </div>
            <div>
                <h5 className="text-[12px] font-black uppercase tracking-[0.4em] text-amber-400">Technical Production Blueprint</h5>
                <p className="text-[10px] text-zinc-500 font-bold uppercase mt-1">Industrial Ready Spec Sheet</p>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
             <div className="bg-white/5 p-5 rounded-2xl border border-white/5 flex flex-col justify-center">
               <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest block mb-2">DPI Target</span>
               <span className="text-sm font-bold text-white flex items-center gap-2"><FileCheck className="w-3 h-3 text-amber-400" /> 300 Optimized</span>
             </div>
             <div className="bg-white/5 p-5 rounded-2xl border border-white/5 flex flex-col justify-center">
               <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest block mb-2">Color Matrix</span>
               <span className="text-sm font-bold text-white flex items-center gap-2"><Palette className="w-3 h-3 text-amber-400" /> CMYK Vector</span>
             </div>
             <div className="bg-white/5 p-5 rounded-2xl border border-white/5 flex flex-col justify-center">
               <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest block mb-2">Repeat Logic</span>
               <span className="text-sm font-bold text-white truncate flex items-center gap-2"><MapPin className="w-3 h-3 text-amber-400" /> {pattern.prompt.split('Repeat: ')[1]?.split(' ')[0] || 'Seamless'}</span>
             </div>
             <div className="bg-white/5 p-5 rounded-2xl border border-white/5 flex flex-col justify-center">
               <span className="text-[8px] font-black text-zinc-500 uppercase tracking-widest block mb-2">Export Class</span>
               <span className="text-sm font-bold text-white">Lossless PNG</span>
             </div>
          </div>
        </div>

        {/* Cultural Synthesis - NOW SECOND */}
        <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-black/[0.02]">
          <div className="flex items-center gap-5 pb-8 border-b border-gray-100 mb-8">
            <div className="bg-amber-950 p-4 rounded-2xl">
                <BookOpen className="w-6 h-6 text-white" />
            </div>
            <div>
                <h5 className="text-[12px] font-black uppercase tracking-[0.4em] text-amber-950">Artisan Narrative & Cultural Logic</h5>
                <p className="text-[10px] text-gray-400 font-bold uppercase mt-1">Heritage Reasoning Engine</p>
            </div>
          </div>

          <div className="relative">
            <div className="absolute -left-6 top-0 bottom-0 w-1 bg-amber-950/10 rounded-full" />
            <p className="text-[16px] text-gray-700 leading-relaxed font-medium italic text-pretty pl-4">
              "{pattern.reasoning}"
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

